method MaxProfit(a: array<int>) returns (best: int)
  requires a.Length >= 2
  ensures exists i, j :: 0 <= i < j < a.Length && best == a[j] - a[i]
  ensures forall i, j :: 0 <= i < j < a.Length ==> best >= a[j] - a[i]
{
  best := a[1] - a[0];
  var minIdx := if a[0] <= a[1] then 0 else 1;
  ghost var bi, bj := 0, 1;
  var j := 2;
  while j < a.Length
    invariant 2 <= j <= a.Length
    invariant 0 <= minIdx < j
    invariant 0 <= bi < bj < j
    invariant best == a[bj] - a[bi]
    invariant forall i :: 0 <= i < j ==> a[minIdx] <= a[i]
    invariant forall i, k :: 0 <= i < k < j ==> best >= a[k] - a[i]
  {
    if a[j] - a[minIdx] > best {
      best := a[j] - a[minIdx];
      bi := minIdx;
      bj := j;
    }
    if a[j] < a[minIdx] {
      minIdx := j;
    }
    j := j + 1;
  }
}

